    if not expression.strip():
        raise ValueError("Empty input")

    tokens = _tokenize(expression)
    return _parse_expression(tokens)


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        assert node.value is not None
        return node.value
    elif node.type == "binop":
        assert node.left is not None and node.right is not None
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown binary operator: {node.op}")
    elif node.type == "unary":
        assert node.operand is not None
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")


def _tokenize(expression: str) -> list:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c.isdigit() or c == ".":
            num_str = []
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                num_str.append(expression[i])
                i += 1
            tokens.append(("number", float("".join(num_str))))
        elif c in "+-*/()":
            tokens.append(("operator", c))
            i += 1
        else:
            raise ValueError(f"Invalid token: {c}")

    return tokens


def _parse_expression(tokens: list) -> ASTNode:
    return _parse_additive(tokens)


def _parse_additive(tokens: list) -> ASTNode:
    node = _parse_multiplicative(tokens)

    while tokens and tokens[0][1] in ("+", "-"):
        op = tokens.pop(0)[1]
        right = _parse_multiplicative(tokens)
        node = ASTNode(type="binop", op=op, left=node, right=right)

    return node


def _parse_multiplicative(tokens: list) -> ASTNode:
    node = _parse_unary(tokens)

    while tokens and tokens[0][1] in ("*", "/"):
        op = tokens.pop(0)[1]
        right = _parse_unary(tokens)
        node = ASTNode(type="binop", op=op, left=node, right=right)

    return node


def _parse_unary(tokens: list) -> ASTNode:
    if tokens and tokens[0][1] == "-":
        tokens.pop(0)
        operand = _parse_primary(tokens)
        return ASTNode(type="unary", op="-", operand=operand)

    return _parse_primary(tokens)


def _parse_primary(tokens: list) -> ASTNode:
    if not tokens:
        raise ValueError("Unexpected end of expression")

    token_type, token_value = tokens[0]

    if token_type == "number":
        tokens.pop(0)
        return ASTNode(type="number", value=token_value)
    elif token_value == "(":
        tokens.pop(0)
        node = _parse_expression(tokens)
        if not tokens or tokens[0][1] != ")":
            raise ValueError("Unmatched parenthesis")
        tokens.pop(0)
        return node
    else:
        raise ValueError(f"Unexpected token: {token_value}")
